const items = $input.all().map(i => i.json);
const today = new Date();
today.setHours(0, 0, 0, 0);
const horizon = new Date(today);
horizon.setDate(horizon.getDate() + 30);

function tagFor(dateStr) {
  const d = new Date(dateStr);
  const diff = Math.round((d - today) / 86400000);
  if (diff < 0) return { days: diff, cls: 'red' };
  if (diff <= 7) return { days: diff, cls: 'orange' };
  return { days: diff, cls: 'yellow' };
}

const faellig = items
  .filter(a => {
    if (!a.Naechste_Pruefung) return false;
    const d = new Date(a.Naechste_Pruefung);
    return d <= horizon;
  })
  .map(a => ({ ...a, _tag: tagFor(a.Naechste_Pruefung) }))
  .sort((a, b) => a._tag.days - b._tag.days);

if (faellig.length === 0) {
  return [{ json: { anzahl: 0, betreff: '', html: '' } }];
}

const colors = { red: '#ef4444', orange: '#f97316', yellow: '#eab308' };

const rows = faellig.map(a => {
  const color = colors[a._tag.cls];
  const days = a._tag.days;
  const dayLabel = days < 0
    ? (Math.abs(days) === 1 ? '1 Tag ueberfaellig' : Math.abs(days) + ' Tage ueberfaellig')
    : days === 0 ? 'Heute faellig' : ('in ' + days + (days === 1 ? ' Tag' : ' Tagen'));
  return '<tr>'
    + '<td style="padding:8px;border-bottom:1px solid #e5e7eb">' + (a.Seriennummer || '-') + '</td>'
    + '<td style="padding:8px;border-bottom:1px solid #e5e7eb">' + (a.Ausruestungstyp || '-') + '</td>'
    + '<td style="padding:8px;border-bottom:1px solid #e5e7eb">' + (a.Kamerad || '-') + '</td>'
    + '<td style="padding:8px;border-bottom:1px solid #e5e7eb;color:' + color + ';font-weight:600">' + dayLabel + '</td>'
    + '</tr>';
}).join('');

const ueberfaellig = faellig.filter(a => a._tag.days < 0).length;
const rest = faellig.length - ueberfaellig;

const betreff = ueberfaellig > 0
  ? 'PSA: ' + ueberfaellig + ' ueberfaellige + ' + rest + ' bald faellige Pruefungen'
  : 'PSA: ' + faellig.length + ' Pruefung' + (faellig.length > 1 ? 'en' : '') + ' in den naechsten 30 Tagen';

const html = '<html><body style="font-family:sans-serif;max-width:600px;margin:0 auto;padding:20px;color:#111827">'
  + '<h2 style="margin-top:0;color:#1e3a5f">PSA-Pruefungs-Reminder</h2>'
  + '<p>Folgende Ausruestungsstuecke haben in den naechsten 30 Tagen eine faellige oder ueberfaellige Pruefung:</p>'
  + '<table style="width:100%;border-collapse:collapse;font-size:14px">'
  + '<thead><tr style="background:#f3f4f6;text-align:left">'
  + '<th style="padding:8px">Seriennummer</th>'
  + '<th style="padding:8px">Typ</th>'
  + '<th style="padding:8px">Kamerad</th>'
  + '<th style="padding:8px">Faelligkeit</th>'
  + '</tr></thead>'
  + '<tbody>' + rows + '</tbody>'
  + '</table>'
  + '<p style="margin-top:24px;font-size:12px;color:#6b7280">Dieser Reminder wird automatisch jeden Montag versandt.<br>'
  + '<a href="https://IHRE-PSA-URL" style="color:#3b82f6">PSA-Verwaltung oeffnen</a></p>'
  + '</body></html>';

return [{ json: { anzahl: faellig.length, betreff, html } }];

